mapper.select:
SELECT
    ${tableSpec.orderIdSelect},
    ${tableSpec.orderNoSelect},
    ${tableSpec.orderStatusSelect},
    ${tableSpec.payStatusSelect},
    ${tableSpec.orderTimeSelect},
    ${tableSpec.payTimeSelect},
    ${tableSpec.totalAmountSelect},
    ${tableSpec.buyerNicknameSelect}
FROM ${tableSpec.tableName}
WHERE ${tableSpec.orderTimeColumn} >= #{startTime}
  AND ${tableSpec.orderTimeColumn} < #{endTime}

    AND ${tableSpec.orderNoColumn} LIKE CONCAT('%', #{keyword}, '%')

ORDER BY ${tableSpec.orderTimeColumn} DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM ${tableSpec.tableName}
WHERE ${tableSpec.orderTimeColumn} >= #{startTime}
  AND ${tableSpec.orderTimeColumn} < #{endTime}

    AND ${tableSpec.orderNoColumn} LIKE CONCAT('%', #{keyword}, '%')

SELECT
    ${tableSpec.statDateSelect},
    ${tableSpec.orderCountSelect},
    ${tableSpec.paidOrderCountSelect},
    ${tableSpec.totalAmountSelect},
    ${tableSpec.paidAmountSelect},
    ${tableSpec.refundAmountSelect}
FROM ${tableSpec.tableName}
WHERE ${tableSpec.statDateColumn} >= #{startDate}
  AND ${tableSpec.statDateColumn} <= #{endDate}
ORDER BY ${tableSpec.statDateColumn} ASC

SELECT CAST(MAX(${tableSpec.statDateColumn}) AS CHAR) AS latestStatDate, COALESCE(SUM(${tableSpec.orderCountExpression}), 0) AS orderCount, COALESCE(SUM(${tableSpec.paidOrderCountExpression}), 0) AS paidOrderCount, COALESCE(SUM(${tableSpec.unpaidOrderCountExpression}), 0) AS unpaidOrderCount, COALESCE(SUM(${tableSpec.closedOrderCountExpression}), 0) AS closedOrderCount, COALESCE(SUM(${tableSpec.totalAmountExpression}), 0) AS totalAmount, COALESCE(SUM(${tableSpec.paidAmountExpression}), 0) AS paidAmount, COALESCE(SUM(${tableSpec.refundAmountExpression}), 0) AS refundAmount, CASE WHEN COALESCE(SUM(${tableSpec.orderCountExpression}), 0) = 0 THEN 0 ELSE ROUND( CAST(COALESCE(SUM(${tableSpec.paidOrderCountExpression}), 0) AS DECIMAL(18, 4)) / COALESCE(SUM(${tableSpec.orderCountExpression}), 0), 4 ) END AS paySuccessRate FROM ${tableSpec.tableName}
${tableSpec.statDateColumn} >= #{startDate}
AND
${tableSpec.statDateColumn} <= #{endDate}

SELECT CAST(log_id AS CHAR) AS logId, CAST(job_code AS CHAR) AS jobCode, CAST(job_name AS CHAR) AS jobName, CAST(run_status AS CHAR) AS runStatus, CAST(message AS CHAR) AS message, synced_order_count AS syncedOrderCount, synced_payment_order_count AS syncedPaymentOrderCount, synced_notify_log_count AS syncedNotifyLogCount, started_at AS startedAt, finished_at AS finishedAt, duration_ms AS durationMs, created_at AS createdAt FROM dw_sync_job_log
WHERE job_code = #{jobCode}
ORDER BY started_at DESC LIMIT #{limit}
